    UT_hash_handle hh;
} HashItem; 

HashItem *hashFindItem(HashItem **obj, int key) {
    HashItem *pEntry = NULL;
    HASH_FIND_INT(*obj, &key, pEntry);
    return pEntry;
}

bool hashAddItem(HashItem **obj, int key) {
    if (hashFindItem(obj, key)) {
        return false;
    }
    HashItem *pEntry = (HashItem *)malloc(sizeof(HashItem));
    pEntry->key = key;
    HASH_ADD_INT(*obj, key, pEntry);
    return true;
}

void hashFree(HashItem **obj) {
    HashItem *curr = NULL, *tmp = NULL;
    HASH_ITER(hh, *obj, curr, tmp) {
        HASH_DEL(*obj, curr);  
        free(curr);
    }
}

typedef struct UnionFind {
    int *parent;
    int *rank;
} UnionFind;

struct UnionFind* creatUnionFind(int n) {
    UnionFind *obj = (UnionFind *)malloc(sizeof(UnionFind));
    obj->parent = (int *)calloc(n, sizeof(int));
    for (int i = 0; i < n; i++) {
        obj->parent[i] = i;
    }
    obj->rank = (int *)calloc(n, sizeof(int));
    return obj;
}

int find(const UnionFind* obj, int x) {
    if (obj->parent[x] != x) {
        obj->parent[x] = find(obj, obj->parent[x]);
    }
    return obj->parent[x];
}

void freeUnionFind(UnionFind* obj) {
    free(obj->parent);
    free(obj->rank);
    free(obj);
}

void uni(UnionFind* obj, int x, int y) {
    int rootx = find(obj, x);
    int rooty = find(obj, y);
    if (rootx != rooty) {
        if (obj->rank[rootx] > obj->rank[rooty]) {
            obj->parent[rooty] = rootx;
        } else if (obj->rank[rootx] < obj->rank[rooty]) {
            obj->parent[rootx] = rooty;
        } else {
            obj->parent[rooty] = rootx;
            obj->rank[rootx]++;
        }
    }
}

int closedIsland(int** grid, int gridSize, int* gridColSize) {
    int m = gridSize, n = gridColSize[0];
    UnionFind *uf = creatUnionFind(m * n);

    for (int i = 0; i < m; i++) {
        if (grid[i][0] == 0) {
            uni(uf, i * n, 0);
        }
        if (grid[i][n - 1] == 0) {
            uni(uf, i * n + n - 1, 0);
        }
    }
    for (int j = 1; j < n - 1; j++) {
        if (grid[0][j] == 0) {
            uni(uf, j, 0);
        }
        if (grid[m - 1][j] == 0) {
            uni(uf, (m - 1) * n + j, 0);
        }
    }
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 0) {
                if (i > 0 && grid[i - 1][j] == 0) {
                    uni(uf, i * n + j, (i - 1) * n + j);
                }
                if (j > 0 && grid[i][j - 1] == 0) {
                    uni(uf, i * n + j, i * n + j - 1);
                }
            }
        }
    }

    HashItem *cnt = NULL;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 0) {
                hashAddItem(&cnt, find(uf, i * n + j));
            }
        }
    }
    int total = HASH_COUNT(cnt);
    if (hashFindItem(&cnt, find(uf, 0))) {
        total--;
    }
    freeUnionFind(uf);
    hashFree(&cnt);
    return total;
}

