class Solution {
public:
    long long tot=0;
    priority_queue<int>Q;
    bool isPossible(vector<int>& target) {
        if ((int)target.size()==1) return target[0]==1;
        while (!Q.empty()) Q.pop();
        for(auto x:target) Q.push(x),tot+=x;
        while (!Q.empty()){
            int x=Q.top();Q.pop();
            if (x==1) break;
            if (x*2-tot<1) return false;
            long long left=tot-x;
            long long y=Q.top();
            long long k;
            if (y==1) k=(x-y+left-1)/left;
            else k=(x-y)/left+1;
            x-=k*left;
            if (x<=0) return false;
            tot-=k*left;
            Q.push(x);
        }
        return true;
    }
};

public class Solution {
    public int[] SortByBits(int[] arr) {
        int GetBitCount(int x) {
            int res = 0;
            while (x > 0) {
                res += (x & 1);
                x >>= 1;
            }
            return res;
        }

        var bitCounts = new int[10001];
        foreach (int x in arr) {
            bitCounts[x] = GetBitCount(x);
        }

        Array.Sort(arr, (x, y) => {
            if (bitCounts[x] != bitCounts[y]) {
                return bitCounts[x].CompareTo(bitCounts[y]);
            }
            return x.CompareTo(y);
        });

        return arr;
    }
}

