    bool *res = (bool *)malloc(sizeof(bool) * queriesSize);
    for (int i = 0; i < queriesSize; i++) {
        int *query = queries[i];
        res[i] = isPre[query[0]][query[1]];
    }
    for (int i = 0; i < numCourses; i++) {
        free(g[i]);
        free(isPre[i]);
    }
    *returnSize = queriesSize;
    return res;
}

