            // 每一轮迭代后，将学习率进行衰减
            alpha *= (1.0 - decay);
        }

        // 判断是否结束迭代
        if (sqrt((x - xPrev) * (x - xPrev) + (y - yPrev) * (y - yPrev)) < eps) {
            break;
        }
    }

